pub fn parse<T>(
    input: &str,
    file_name: T,
    user_actions: &mut VerylGrammar,
) -> Result<ParseTree, ParolError>
where
    T: AsRef<Path>,
{
    use parol_runtime::{
        parser::{parse_tree_type::SynTree, parser_types::SynTreeFlavor},
        syntree::Builder,
    };
    let mut builder = Builder::<SynTree, SynTreeFlavor>::new_with();
    parse_into(input, &mut builder, file_name, user_actions)?;
    Ok(builder.build()?)
}
#[allow(dead_code)]
pub fn parse_into<'t, T: TreeConstruct<'t>>(
    input: &'t str,
    tree_builder: &mut T,
    file_name: impl AsRef<Path>,
    user_actions: &mut VerylGrammar,
) -> Result<(), ParolError>
where
    ParolError: From<T::Error>,
{
    use veryl_grammar_scanner::VerylGrammarScanner;
    let mut llk_parser = LLKParser::new(
        768,
        LOOKAHEAD_AUTOMATA,
        PRODUCTIONS,
        TERMINAL_NAMES,
        NON_TERMINALS,
    );
    llk_parser.trim_parse_tree();
    llk_parser.set_max_parsing_depth(1152);
    let scanner = VerylGrammarScanner::new();
    // Initialize wrapper
    let mut user_actions = VerylGrammarAuto::new(user_actions);
    llk_parser.parse_into(
        tree_builder,
        TokenStream::new_with_skip_tokens(
            input,
            file_name,
            scanner.scanner_impl.clone(),
            &VerylGrammarScanner::match_function,
            MAX_K,
            SKIP_TOKENS_BY_SCANNER_STATE,
        )
        .unwrap(),
        &mut user_actions,
    )
}
